// pages/admin/CategoryManage.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';

const CategoryManage = () => {
  const [categories, setCategories] = useState([]);
  const [categoryName, setCategoryName] = useState('');
  const [editingId, setEditingId] = useState(null);

  const token = localStorage.getItem('token'); // 🔐 Get admin token

  // Axios config with auth header
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  // Fetch categories (GET doesn't need token)
  const fetchCategories = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/categories');
      setCategories(res.data);
    } catch (err) {
      console.error('Error fetching categories:', err);
    }
  };

  useEffect(() => {
    fetchCategories();
  }, []);

  // Add or Update Category
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!categoryName.trim()) return;

    try {
      if (editingId) {
        await axios.put(
          `http://localhost:5000/api/categories/${editingId}`,
          { name: categoryName },
          config
        );
      } else {
        await axios.post(
          'http://localhost:5000/api/categories',
          { name: categoryName },
          config
        );
      }

      setCategoryName('');
      setEditingId(null);
      fetchCategories();
    } catch (err) {
      console.error('Error saving category:', err);
    }
  };

  // Edit
  const handleEdit = (cat) => {
    setCategoryName(cat.name);
    setEditingId(cat.id);
  };

  // Delete
  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this category?')) return;

    try {
      await axios.delete(`http://localhost:5000/api/categories/${id}`, config);
      fetchCategories();
    } catch (err) {
      console.error('Error deleting category:', err);
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-bold mb-4">Manage Categories</h2>

      {/* Form */}
      <form onSubmit={handleSubmit} className="mb-6">
        <input
          type="text"
          value={categoryName}
          onChange={(e) => setCategoryName(e.target.value)}
          placeholder="Category name"
          className="p-2 border rounded mr-2"
        />
        <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">
          {editingId ? 'Update' : 'Add'}
        </button>
        {editingId && (
          <button
            type="button"
            onClick={() => {
              setEditingId(null);
              setCategoryName('');
            }}
            className="ml-2 text-gray-600"
          >
            Cancel
          </button>
        )}
      </form>

      {/* Table */}
      <table className="w-full bg-white shadow rounded">
        <thead>
          <tr className="bg-gray-200">
            <th className="text-left p-2">#</th>
            <th className="text-left p-2">Category Name</th>
            <th className="text-left p-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {categories.map((cat, index) => (
            <tr key={cat.id} className="border-t">
              <td className="p-2">{index + 1}</td>
              <td className="p-2">{cat.name}</td>
              <td className="p-2">
                <button
                  onClick={() => handleEdit(cat)}
                  className="text-blue-600 mr-4"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(cat.id)}
                  className="text-red-600"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
          {categories.length === 0 && (
            <tr>
              <td colSpan="3" className="p-4 text-center text-gray-500">
                No categories found.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default CategoryManage;
